import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.resolve(__dirname, '..');
const gitHooksDir = path.join(projectRoot, '.git', 'hooks');
const preCommitHookPath = path.join(gitHooksDir, 'pre-commit');

const hookContent = `#!/bin/sh
# Auto-generated by Nexus-DevFlow
echo "🔄 Auto-updating Graphify codebase knowledge graph..."
npm run graphify:update
`;

try {
  if (!fs.existsSync(gitHooksDir)) {
    console.error('Error: .git directory not found or hooks folder is missing.');
    process.exit(1);
  }
  fs.writeFileSync(preCommitHookPath, hookContent, { mode: 0o755 });
  console.log('✅ pre-commit hook installed successfully!');
} catch (error) {
  console.error(`Failed to install git hook: ${error.message}`);
  process.exit(1);
}
